19	const PROCESSING_FEE = 5;
20	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
21	
22	const BASE_PREMIUMS: Record<string, number> = {
23	  sword: 100,
24	  amulet: 60,
25	  staff: 80,
26	  potion: 40,
27	  rune: 25,
28	};
29	
30	const COMPONENT_TYPES = new Set(["rune"]);
31	const BLOCK_SIZE = 3;
32	const BLOCK_BASE_PREMIUM = 60;
33	
34	const itemsBasePremium = (items: Item[]): number => {
35	  let total = 0;
36	  const componentCounts: Record<string, number> = {};
37	  for (const item of items) {
38	    if (COMPONENT_TYPES.has(item.type)) {
39	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
40	    } else {
41	      total += BASE_PREMIUMS[item.type];
42	    }
43	  }
44	  for (const [type, count] of Object.entries(componentCounts)) {
45	    if (count === BLOCK_SIZE) {
46	      total += BLOCK_BASE_PREMIUM;
47	    } else {
48	      total += count * BASE_PREMIUMS[type];
49	    }
50	  }
51	  return total;
52	};
53	
54	const quoteStep = (step: QuoteStep): QuoteResult => {
55	  const base = itemsBasePremium(step.items);
56	  const withFirstContract = base + base * FIRST_CONTRACT_SURCHARGE_RATE;
57	  return { premium: Math.ceil(withFirstContract + PROCESSING_FEE) };
58	};
59	
60	export const runScenario = (scenario: Scenario): ScenarioResult => {
61	  return { results: scenario.steps.map(quoteStep) };
62	};
